from datetime import datetime, timedelta
import pytest
from app.ai.stages import extract_viewing_datetime


def test_extract_viewing_datetime_with_explicit_pm_time_and_date():
    now = datetime(2024, 4, 25, 10, 0)  # April 25, 2024, 10:00 AM
    messages = [
        {"message": "Looking forward to the appointment on 26/04 at 3pm."}
    ]
    result = extract_viewing_datetime(messages, now=now)
    expected = datetime(2024, 4, 26, 15, 0)
    assert result == expected


def test_extract_viewing_datetime_with_implicit_pm_time_and_today_date_rollover():
    now = datetime(2024, 4, 25, 18, 0)  # 6 PM
    messages = [
        {"message": "See you at 7"}
    ]
    # 7 without am/pm suffix between 1 and 7 should be interpreted as 7pm
    # But 7pm today is 19:00, which is after 18:00 now, so same day
    expected = datetime(2024, 4, 25, 19, 0)
    result = extract_viewing_datetime(messages, now=now)
    assert result == expected


def test_extract_viewing_datetime_with_time_before_now_rolls_to_next_day():
    now = datetime(2024, 4, 25, 20, 0)  # 8 PM
    messages = [
        {"message": "Appointment confirmed at 7am tomorrow."}
    ]
    # 7am today is before now, so should roll over to tomorrow
    expected = datetime(2024, 4, 26, 7, 0)
    result = extract_viewing_datetime(messages, now=now)
    assert result == expected


def test_extract_viewing_datetime_ignores_time_overlapping_date():
    now = datetime(2024, 4, 25, 10, 0)
    # The time pattern overlaps with the date pattern "25/04"
    messages = [
        {"message": "Appointment on 25/04 at 14:00."}
    ]
    # The "14:00" time does not overlap with date span "25/04", so should be detected
    expected = datetime(2024, 4, 25, 14, 0)
    result = extract_viewing_datetime(messages, now=now)
    assert result == expected

