    now = datetime(2024, 6, 10, 15, 0)  # June 10, 2024, 3:00 PM
    messages = [
        {"message": "Let's meet tomorrow at 3pm"}
    ]
    expected = datetime(2024, 6, 11, 15, 0)  # June 11, 2024, 3:00 PM
