def test_extract_time_without_am_pm_suffix_after_7am_adds_pm():
    now = datetime(2024, 6, 10, 8, 0)  # 8:00 AM
    messages = [
        {"message": "See you at 6:30"}
    ]
    expected = datetime(2024, 6, 10, 18, 30)  # 6:30 PM same day
    result = extract_viewing_datetime(messages, now=now)
    assert result == expected

def test_extract_time_with_am_suffix_and_hour_12_is_midnight():
    now = datetime(2024, 6, 10, 23, 0)  # 11:00 PM
    messages = [
        {"message": "Appointment at 12am"}
    ]
    expected = datetime(2024, 6, 11, 0, 0)  # Next day midnight
    result = extract_viewing_datetime(messages, now=now)
    assert result == expected

def test_extract_date_from_numeric_date_and_time_before_now_rolls_to_next_year():
    now = datetime(2024, 12, 31, 10, 0)  # Dec 31, 2024, 10:00 AM
    messages = [
        {"message": "See you on 31/12 at 9am"}
    ]
    # The 31/12 without year is interpreted as Dec 31 next year because candidate < now.date()
    expected = datetime(2025, 12, 31, 9, 0)
    result = extract_viewing_datetime(messages, now=now)
    assert result == expected

